import { cn } from '@/utils/cn';
import { Component, mergeProps, ParentComponent, Show, Switch } from 'solid-js';
// No custom CSS needed — uses DaisyUI's built-in .skeleton class

// ─── Type definitions ─────────────────────────────────────────────────────────

/** Layout skeleton: giao diện phức tạp gồm nhiều element */
type LayoutVariant =
  | 'cardImage' // Card với ảnh trên + text dưới
  | 'cardHorizontal' // Card nằm ngang: ảnh trái, nội dung phải
  | 'profile' // Avatar tròn + tên + mô tả
  | 'article' // Tiêu đề + đoạn văn nhiều dòng
  | 'feedItem' // Item list: avatar trái + text dọc
  | 'stat'; // Khối thống kê: label + số lớn + sublabel

/** Shape skeleton: hình khối đơn giản với kích thước preset */
type ShapeVariant =
  | 'rectangle' // Hình chữ nhật (mặc định w-full)
  | 'square' // Hình vuông (w = h)
  | 'circle' // Hình tròn
  | 'textLine' // Một dòng text
  | 'textParagraph'; // Đoạn text 3–4 dòng

type LayoutSkeletonProps = {
  type: 'layout';
  variant?: LayoutVariant;
  enabled: boolean;
};

type ShapeSkeletonProps = {
  type: 'shape';
  variant?: ShapeVariant;
  enabled: boolean;
};

/** Custom skeleton: user toàn quyền cấu hình — class áp thẳng lên element skeleton */
type CustomSkeletonProps = {
  type: 'custom';
  enabled: boolean;
  class: string; // bắt buộc — định nghĩa hình dạng, kích thước, bo góc
};

export type SkeletonProps = LayoutSkeletonProps | ShapeSkeletonProps | CustomSkeletonProps;

// ─── Main component ───────────────────────────────────────────────────────────

export const Skeleton: ParentComponent<SkeletonProps> = rawProps => {
  const p = mergeProps({ variant: 'card-image' } as const, rawProps);

  return (
    <Show when={p.enabled} fallback={p.children}>
      {p.type === 'custom' ? (
        <div class={cn('skeleton', p.class)} />
      ) : (
        <SkeletonDisplay
          type={p.type}
          variant={(p as LayoutSkeletonProps | ShapeSkeletonProps).variant as never}
        />
      )}
    </Show>
  );
};

// ─── Display switcher ─────────────────────────────────────────────────────────

type SkeletonDisplayProps = {
  type: 'layout' | 'shape';
  variant: LayoutVariant | ShapeVariant;
  class?: string;
};

const SkeletonDisplay: Component<SkeletonDisplayProps> = p => {
  if (p.type === 'shape') {
    return <ShapeSkeleton variant={p.variant as ShapeVariant} />;
  }
  return <LayoutSkeleton variant={p.variant as LayoutVariant} />;
};

// ─── Layout Skeletons ─────────────────────────────────────────────────────────

const LayoutSkeleton: Component<{ variant?: LayoutVariant }> = p => {
  switch (p.variant) {
    case 'cardImage':
      return (
        <div class="flex flex-col gap-3">
          <div class="skeleton h-40 w-full rounded-lg" />
          <div class="skeleton h-5 w-3/4 rounded" />
          <div class="skeleton h-3.5 w-full rounded" />
          <div class="skeleton h-3.5 w-5/6 rounded" />
          <div class="skeleton h-3.5 w-4/5 rounded" />
        </div>
      );

    case 'cardHorizontal':
      return (
        <div class="flex flex-row items-start gap-4">
          <div class="skeleton size-24 shrink-0 rounded-lg" />
          <div class="flex flex-1 flex-col gap-2.5">
            <div class="skeleton h-5 w-2/3 rounded" />
            <div class="skeleton h-3.5 w-full rounded" />
            <div class="skeleton h-3.5 w-4/5 rounded" />
            <div class="skeleton h-3.5 w-3/4 rounded" />
          </div>
        </div>
      );

    case 'profile':
      return (
        <div class="flex flex-col items-center gap-3">
          <div class="skeleton size-20 shrink-0 rounded-full" />
          <div class="skeleton h-5 w-36 rounded" />
          <div class="skeleton h-3.5 w-48 rounded" />
          <div class="skeleton h-3.5 w-40 rounded" />
        </div>
      );

    case 'article':
      return (
        <div class="flex flex-col gap-3">
          <div class="skeleton h-7 w-3/4 rounded" />
          <div class="skeleton h-4 w-1/3 rounded" />
          <div class="mt-1 flex flex-col gap-2">
            <div class="skeleton h-3.5 w-full rounded" />
            <div class="skeleton h-3.5 w-full rounded" />
            <div class="skeleton h-3.5 w-11/12 rounded" />
            <div class="skeleton h-3.5 w-full rounded" />
            <div class="skeleton h-3.5 w-4/5 rounded" />
          </div>
        </div>
      );

    case 'feedItem':
      return (
        <div class="flex flex-row items-start gap-3">
          <div class="skeleton size-10 shrink-0 rounded-full" />
          <div class="flex flex-1 flex-col gap-2">
            <div class="skeleton h-4 w-1/3 rounded" />
            <div class="skeleton h-3.5 w-full rounded" />
            <div class="skeleton h-3.5 w-5/6 rounded" />
          </div>
        </div>
      );

    case 'stat':
      return (
        <div class="flex flex-col gap-2">
          <div class="skeleton h-3.5 w-24 rounded" />
          <div class="skeleton h-9 w-32 rounded" />
          <div class="skeleton h-3 w-20 rounded" />
        </div>
      );

    default:
      return (
        <div class="flex flex-col gap-3">
          <div class="skeleton h-40 w-full rounded-lg" />
          <div class="skeleton h-5 w-3/4 rounded" />
          <div class="skeleton h-3.5 w-full rounded" />
        </div>
      );
  }
};

// ─── Shape Skeletons ──────────────────────────────────────────────────────────

const ShapeSkeleton: Component<{ variant?: ShapeVariant }> = p => {
  switch (p.variant) {
    case 'rectangle':
      return <div class="skeleton h-32 w-full rounded-lg" />;

    case 'square':
      return <div class="skeleton size-32 rounded-lg" />;

    case 'circle':
      return <div class="skeleton size-16 rounded-full" />;

    case 'textLine':
      return <div class="skeleton h-4 w-full rounded" />;

    case 'textParagraph':
      return (
        <div class="flex flex-col gap-2">
          <div class="skeleton h-4 w-full rounded" />
          <div class="skeleton h-4 w-11/12 rounded" />
          <div class="skeleton h-4 w-4/5 rounded" />
          <div class="skeleton h-4 w-5/6 rounded" />
        </div>
      );

    default:
      return <div class="skeleton h-32 w-full rounded-lg" />;
  }
};
